import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def pkg_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                m[(name, pkg['id'])] = pkg['resolvedVersion']
    return m

b, a = pkg_map(baseline), pkg_map(after)
changes = []
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv, av = b.get(k), a.get(k)
    if bv != av:
        changes.append((k[0], k[1], bv, av))
if changes:
    for c in changes: print(f'CHANGED: {c}')
else:
    print('All packages resolve identically to baseline.')
"

